	open: boolean;
	onOpenChange: (open: boolean) => void;
	defaultOpen?: boolean;
	children: React.ReactNode;
	dialogProps?: React.ComponentProps<typeof Dialog>;
	drawerProps?: React.ComponentProps<typeof Drawer>;
};

